export const CITY_SEEDS = SEEDS;

export function toCityRecords(seeds: CitySeed[] = SEEDS): Omit<CityRecord, "id">[] {
  return seeds.map((s) => ({
    name: s.name,
    country: s.country,
    lat: s.lat,
    lng: s.lng,
    timezone: s.tz,
    timezoneOffsetHours: s.tzOffset,
    population: s.pop,
    qolIndex: s.qol,
    costIndex: s.cost,
    climate: s.climate,
    iso2: s.iso2,
    aliases: s.aliases,
  }));
}

export async function seedCitiesIfEmpty(): Promise<number> {
  const { db } = await import("@/lib/db");
  const count = await db.city.count();
  const expected = SEEDS.length;
  if (count >= expected) return count;

  // Если городов меньше ожидаемого — пересидируем (удаляем старые + вставляем все)
  if (count > 0 && count < expected) {
    await db.citySocialProof.deleteMany();
    await db.city.deleteMany();
  }

  const records = toCityRecords();
  await db.city.createMany({
    data: records.map((r) => ({
      name: r.name,
      country: r.country,
      lat: r.lat,
      lng: r.lng,
      timezone: r.timezone,
      tzOffsetHours: r.timezoneOffsetHours,
      population: r.population ?? null,
      qolIndex: r.qolIndex ?? null,
      costIndex: r.costIndex ?? null,
      climate: r.climate ?? null,
      iso2: r.iso2 ?? null,
      aliases: (r as { aliases?: string }).aliases ?? null,
    })),
  });

  // Social proof для top-3 (привязываем к реальным city.id через name lookup)
  const lisbon = await db.city.findFirst({ where: { name: "Lisbon" } });
  const tokyo = await db.city.findFirst({ where: { name: "Tokyo" } });
  const buenosAires = await db.city.findFirst({ where: { name: "Buenos Aires" } });
  const proofData: Array<{ cityId: string; chosenCount: number; editorPick?: boolean; anchorCity?: boolean }> = [];
  if (lisbon) proofData.push({ cityId: lisbon.id, chosenCount: 1842, anchorCity: true });
  if (tokyo) proofData.push({ cityId: tokyo.id, chosenCount: 1456, editorPick: true });
  if (buenosAires) proofData.push({ cityId: buenosAires.id, chosenCount: 1203 });
  if (proofData.length > 0) {
    await db.citySocialProof.createMany({ data: proofData });
  }
  return records.length;
}
